const d = JSON.parse(msg.payload);
if (!d.device_id || !d.device_type) return null;
msg.payload = d;
msg.device_type = d.device_type;
return msg;

const d = msg.payload;
const t = d.device_type;

if (t === 'water') {
  d.flow_rate_ls = +(d.flow_rate_m3h / 3.6).toFixed(3);
  if (d.ph_value !== undefined && (d.ph_value < 6.5 || d.ph_value > 8.5)) {
    node.warn(`pH alarm: ${d.ph_value} on ${d.device_id}`);
    d.ph_alarm = true;
  }
  d.conductivity_alarm = d.conductivity_us > 1000;
}

if (t === 'fuel') {
  if (d.fuel_flow_lh > 0.1 && d.fuel_level_liters) {
    d.autonomy_hours = +(d.fuel_level_liters / d.fuel_flow_lh).toFixed(1);
  }
  d.level_low_alarm = d.fuel_level_pct < 20;
  if (d.level_low_alarm) node.warn(`LOW FUEL: ${d.fuel_level_pct}% on ${d.device_id}`);
}

if (t === 'steam') {
  if (d.steam_flow_kgh && d.steam_enthalpy_kjkg) {
    d.thermal_power_kw = +((d.steam_flow_kgh / 3600) * d.steam_enthalpy_kjkg).toFixed(1);
  }
  d.pressure_alarm = d.steam_pressure_bar > 12.0;
  d.efficiency_alarm = d.boiler_efficiency_pct < 80.0;
  if (d.pressure_alarm) node.warn(`Steam pressure high: ${d.steam_pressure_bar} bar on ${d.device_id}`);
}

msg.payload = d;
return msg;

const d = msg.payload;
const t = d.device_type;
const ts = new Date(d.ts).toISOString();

const metricMap = {
  water: [
    ['flow_rate_m3h', d.flow_rate_m3h],
    ['total_volume_m3', d.total_volume_m3],
    ['pressure_bar', d.pressure_bar],
    ['temperature_c', d.temperature_c],
    ['conductivity_us', d.conductivity_us],
    ['ph_value', d.ph_value],
    ['valve_position_pct', d.valve_position_pct],
    ['flow_rate_ls', d.flow_rate_ls],
  ],
  fuel: [
    ['fuel_flow_lh', d.fuel_flow_lh],
    ['fuel_level_pct', d.fuel_level_pct],
    ['fuel_level_liters', d.fuel_level_liters],
    ['fuel_pressure_bar', d.fuel_pressure_bar],
    ['fuel_temperature_c', d.fuel_temperature_c],
    ['specific_consumption', d.specific_consumption],
    ['autonomy_hours', d.autonomy_hours],
  ],
  steam: [
    ['steam_flow_kgh', d.steam_flow_kgh],
    ['steam_pressure_bar', d.steam_pressure_bar],
    ['steam_temperature_c', d.steam_temperature_c],
    ['steam_enthalpy_kjkg', d.steam_enthalpy_kjkg],
    ['steam_energy_kwh', d.steam_energy_kwh],
    ['thermal_power_kw', d.thermal_power_kw],
    ['boiler_efficiency_pct', d.boiler_efficiency_pct],
    ['blowdown_conductivity', d.blowdown_conductivity],
    ['makeup_water_m3h', d.makeup_water_m3h],
  ],
};

const metrics = metricMap[t] || [];
const messages = metrics
  .filter(([_, v]) => v !== undefined && v !== null)
  .map(([metric, value]) => ({
    payload: {
      query: 'INSERT INTO raw_measurements(time,device_id,device_type,site_id,metric,value,quality) VALUES($1,$2,$3,$4,$5,$6,$7)',
      params: [ts, d.device_id, t, d.site_id, metric, value, d.quality]
    }
  }));
return [messages];

function regsToFloat(hi, lo) {
  const buf = new ArrayBuffer(4);
  const view = new DataView(buf);
  view.setUint16(0, hi);
  view.setUint16(2, lo);
  return view.getFloat32(0, false);
}
const regs = msg.payload.data;
if (!regs || regs.length < 2) return null;
const kw_modbus = regsToFloat(regs[0], regs[1]);
const kw_mqtt = context.get('last_kw_meter_01') || 0;
if (Math.abs(kw_modbus - kw_mqtt) > 5.0) {
  node.warn(`Modbus/MQTT mismatch meter_01: Modbus=${kw_modbus.toFixed(1)} MQTT=${kw_mqtt.toFixed(1)}`);
}
msg.payload = { kw_modbus, kw_mqtt, delta: Math.abs(kw_modbus - kw_mqtt) };
return msg;
